noncompliant:
// Noncompliant: JSInvokable on private method
public class MyComponent
{
    [JSInvokable]
    private void MyMethod() // Should be public
    {
        // ...
    }
}

// Noncompliant: JSInvokable on internal method
public class MyComponent
{
    [JSInvokable]
    internal void MyMethod() // Should be public
    {
        // ...
    }
}

compliant:
// Compliant: JSInvokable on public method
public class MyComponent
{
    [JSInvokable]
    public void MyMethod() // Correctly public
    {
        // ...
    }
}

// Compliant: JSInvokable on public static method
public class MyComponent
{
    [JSInvokable]
    public static Task<string> GetData()
    {
        return Task.FromResult("data");
    }
}
